:root {
  /* TODO: Define design tokens here */
}

.card {
  background: #ffffff;
  padding: 24px;
  border-radius: 12px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  color: #333333;
}

.card h2 {
  font-size: 24px;
  margin-bottom: 16px;
}

.btn {
  background: #667eea;
  color: white;
  padding: 12px 24px;
  border-radius: 8px;
  border: none;
  font-family: 'Inter', sans-serif;
}

[data-theme='dark'] .card {
  background: #1e1e2e;
  color: #cdd6f4;
}

[data-theme='dark'] .btn {
  background: #89b4fa;
}

/* === SETTINGS === */
@layer settings {
  :root {
    --color-primary: #667eea;
    --color-surface: #ffffff;
    --color-text: #333333;
    --spacing-md: 16px;
    --spacing-lg: 24px;
    --radius-md: 8px;
    --radius-lg: 12px;
    --font-sans: system-ui, sans-serif;
  }
}

/* === GENERIC === */
@layer generic {
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: var(--font-sans); background: #f5f5f5; color: var(--color-text); }
}

/* === ELEMENTS === */
@layer elements {
  h1 { font-size: 2rem; }
  a { color: var(--color-primary); }
}

/* === OBJECTS === */
@layer objects {
  .o-container { max-width: 1200px; margin-inline: auto; padding: 0 var(--spacing-md); }
  .o-grid { display: grid; gap: var(--spacing-md); grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); }
  .o-flex { display: flex; gap: var(--spacing-md); flex-wrap: wrap; }
}

/* === COMPONENTS === */
@layer components {
  .c-btn { display: inline-flex; align-items: center; gap: 8px; padding: 12px 24px; border-radius: var(--radius-md); border: none; cursor: pointer; font-weight: 700; }
  .c-btn--primary { background: var(--color-primary); color: white; }
  .c-btn--outline { background: transparent; border: 2px solid var(--color-primary); color: var(--color-primary); }

  .c-card { background: var(--color-surface); border-radius: var(--radius-lg); padding: var(--spacing-lg); box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
  .c-card__title { font-size: 1.25rem; margin-bottom: 8px; }
  .c-card--compact { padding: var(--spacing-md); }

  .c-modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.4); backdrop-filter: blur(4px); align-items: center; justify-content: center; }
  .c-modal-overlay.is-open { display: flex; }
  .c-modal { background: var(--color-surface); border-radius: var(--radius-lg); padding: var(--spacing-lg); max-width: 500px; width: 90%; }
}

/* === UTILITIES === */
@layer utilities {
  .u-mt-md { margin-top: var(--spacing-md); }
  .u-text-center { text-align: center; }
}

/* === PAGE === */
<main class="o-container">
  <div class="o-grid u-mt-md">
    <div class="c-card">
      <h2 class="c-card__title">Card 1</h2>
      <p>Example content</p>
      <div class="o-flex u-mt-md">
        <button class="c-btn c-btn--primary">Primary</button>
        <button class="c-btn c-btn--outline">Outline</button>
      </div>
    </div>
  </div>
</main>
